Below is a **complete, self‑contained binding** that you can drop into a tiny OCaml library (e.g. `blocksci`).  
It contains

* the public OCaml interface (`blocksci.mli`);
* the C‑/C++‑side stubs (`blocksci_stubs.c`);
* a short “how to compile” note at the end.

The design follows the pattern used by high‑performance data‑frame libraries
(e.g. Polars, pandas) :

* The heavy loop lives in C++ – the iterator walks the whole chain once,
  without any OCaml allocation.
* For each block the C++ code **re‑uses a single OCaml custom value** that
  merely points to the current native `Block*`.  
  This avoids the 800 M allocations that would otherwise happen.
* The OCaml callback is invoked through `caml_callback_exn`; any exception
  raised by the user code aborts the walk and is propagated back to the
  caller.

The user‑visible API is deliberately tiny and documented with the
“do‑not‑store the value” contract – exactly the same discipline that
data‑frame libraries ask you to keep when you pass a row view to a
callback.

--------------------------------------------------------------------
### 1️⃣  `blocksci.mli` – public OCaml interface

```ocaml
(** {1 BlockSci OCaml bindings – per‑block iteration} *)

(** Opaque handle that points to a native Block object.  The value is
    **re‑used** for each iteration step; do **not** keep a reference to it
    beyond the call of your callback.  If you need to retain data, copy
    the fields you care about. *)
type block

(** {2 Accessors – cheap, just read the native fields} *)

val block_height   : block -> int
(** Height of the block (0‑based). *)

val block_timestamp : block -> int64
(** Unix‑epoch timestamp of the block (seconds). *)

val block_tx_count : block -> int
(** Number of transactions contained in the block. *)

(** {2 Main iterator} *)

val iter_blocks : (block -> unit) -> unit
(** [iter_blocks f] walks the whole blockchain (≈ 800 M blocks) and
    calls [f b] for each block.  The [block] argument is the same OCaml
    value that is mutated in‑place; the callback must not store it.
    If the callback raises an exception, the walk stops and the exception
    propagates to the caller. *)

(** {2 Convenience – optional helpers} *)

val iter_blocks_exn : (block -> unit) -> unit
(** Same as [iter_blocks] but returns the OCaml exception value
    instead of raising it.  Useful when you want to handle failures
    without long‑jmp.  (Implemented on top of [iter_blocks] in the .ml.) *)
```

--------------------------------------------------------------------
### 2️⃣  `blocksci_stubs.c` – C/C++ glue

> **Important** – this file must be compiled as **C++** (e.g. `g++ … -c`),
> because we include the BlockSci C++ headers and use its iterator class.

```c
/* blocksci_stubs.c ---------------------------------------------------------
 *  OCaml <-> BlockSci binding.
 *  Compile with a C++ compiler (g++ / clang++) and link with the BlockSci
 *  library (e.g. -lblocksci).
 *--------------------------------------------------------------------------*/

#define CAML_NAME_SPACE                /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>            /* for caml_release/acquire if needed */

/* ----------------------------------------------------------------------
 *  Include the BlockSci C++ API.  Replace the include path with the real
 *  one from your installation.
 * ---------------------------------------------------------------------- */
extern "C" {
    /* If BlockSci ships a pure‑C header you can include that instead. */
}
#include "BlockSci.h"   /* <-- your BlockSci header(s) */

/* ----------------------------------------------------------------------
 *  OCaml representation of a native Block*.
 * ---------------------------------------------------------------------- */
struct block_wrapper {
    Block *blk;          /* not owned – lifetime is managed by BlockSci */
};

/* finaliser – nothing to free because we never own the Block* */
static void block_finalize(value v)
{
    /* No action; the pointer is owned by BlockSci's iterator */
}

/* custom operations descriptor */
static struct custom_operations block_ops = {
    "Blocksci.block",
    block_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

/* Helper: allocate a fresh OCaml value that can hold a Block*.
 * This is used only once and then re‑used for every iteration step. */
static value alloc_block_val(void)
{
    value v = caml_alloc_custom(&block_ops,
                                sizeof(struct block_wrapper),
                                0 /* no extra memory for GC */,
                                1 /* finalizer may be called */);
    return v;
}

/* ----------------------------------------------------------------------
 *  Accessor primitives – cheap reads from the native Block*.
 * ---------------------------------------------------------------------- */
CAMLprim value caml_block_height(value v_block)
{
    CAMLparam1(v_block);
    struct block_wrapper *w = (struct block_wrapper *)Data_custom_val(v_block);
    /* Block::height() returns a uint32_t – fits into OCaml int on 64‑bit */
    CAMLreturn(Val_int((int)w->blk->height()));
}

CAMLprim value caml_block_timestamp(value v_block)
{
    CAMLparam1(v_block);
    struct block_wrapper *w = (struct block_wrapper *)Data_custom_val(v_block);
    int64_t ts = w->blk->timestamp();          /* int64_t → OCaml int64 */
    CAMLreturn(caml_copy_int64(ts));
}

CAMLprim value caml_block_tx_count(value v_block)
{
    CAMLparam1(v_block);
    struct block_wrapper *w = (struct block_wrapper *)Data_custom_val(v_block);
    CAMLreturn(Val_int((int)w->blk->tx_count()));
}

/* ----------------------------------------------------------------------
 *  Main iterator: walk the whole blockchain and invoke the OCaml callback.
 *
 *  The callback is called as   caml_callback_exn(cb, block_val)
 *  for each native Block*.  If the callback raises, we propagate the
 *  exception to the OCaml side.
 * ---------------------------------------------------------------------- */
CAMLprim value caml_iter_blocks(value v_cb)
{
    CAMLparam1(v_cb);
    CAMLlocal1(v_block);          /* the reusable OCaml block value */

    /* ------------------------------------------------------------------
     *  Allocate the reusable custom block value once.
     * ------------------------------------------------------------------ */
    v_block = alloc_block_val();
    struct block_wrapper *w = (struct block_wrapper *)Data_custom_val(v_block);

    /* ------------------------------------------------------------------
     *  Create the native iterator.  The exact class name depends on your
     *  BlockSci version – replace with the correct one.
     * ------------------------------------------------------------------ */
    BlockIterator it;   /* default ctor walks the whole chain */

    /* ------------------------------------------------------------------
     *  Iterate.  We deliberately keep the OCaml runtime lock **on** because
     *  the callback is the hot path and the user code may want to call back
     *  into OCaml (e.g. allocate a small array).  If you need true
     *  parallelism you can wrap the loop with caml_release/acquire.
     * ------------------------------------------------------------------ */
    while (it.has_next()) {
        Block *native = it.next();   /* native pointer for this block */
        w->blk = native;             /* mutate the OCaml value in‑place */

        /* Call the user supplied closure.  Use the _exn variant to catch
         * possible OCaml exceptions. */
        value ocaml_res = caml_callback_exn(v_cb, v_block);
        if (Is_exception_result(ocaml_res)) {
            /* Propagate the exception – iteration stops. */
            caml_raise(ocaml_res);
        }
        /* otherwise ignore the unit result */
    }

    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
 *  Optional helper: expose a version that returns the exception value
 *  instead of raising it (used to implement iter_blocks_exn in the .ml).
 * ---------------------------------------------------------------------- */
CAMLprim value caml_iter_blocks_exn(value v_cb)
{
    CAMLparam1(v_cb);
    CAMLlocal1(v_block);
    v_block = alloc_block_val();
    struct block_wrapper *w = (struct block_wrapper *)Data_custom_val(v_block);

    BlockIterator it;
    while (it.has_next()) {
        Block *native = it.next();
        w->blk = native;
        value ocaml_res = caml_callback_exn(v_cb, v_block);
        if (Is_exception_result(ocaml_res)) {
            /* Return the exception value instead of raising it. */
            CAMLreturn(ocaml_res);
        }
    }
    CAMLreturn(Val_int(0));   /* 0 means “no exception” */
}
```

