### 3️⃣  How to build the library (example `dune` stanza)

```lisp
; dune file for the library
(executable
 (name blocksci)
 (modules blocksci)          ; blocksci.ml / blocksci.mli
 (foreign_stubs
  (language c)
  (names blocksci_stubs))
 (libraries
  unix                     ; for caml_threads if you need it
  ctypes)                  ; optional, not used above
 (c_flags (:standard -I/path/to/blocksci/include))
 (cxx_flags (:standard -std=c++17))
 (link_flags (:standard -L/path/to/blocksci/lib -lblocksci))
)
```

*Compile* (with `dune build`) – the `foreign_stubs` stanza tells Dune to
compile `blocksci_stubs.c` with a C++ compiler, link the BlockSci
library, and produce a native OCaml library `blocksci.cma`/`.cmxs`.*

--------------------------------------------------------------------
### 4️⃣  Usage from OCaml

```ocaml
(* blocksci.ml – a tiny wrapper around the primitives in the .mli *)

external block_height   : block -> int    = "caml_block_height"
external block_timestamp: block -> int64 = "caml_block_timestamp"
external block_tx_count : block -> int    = "caml_block_tx_count"

external iter_blocks_c   : (block -> unit) -> unit = "caml_iter_blocks"
external iter_blocks_exn_c : (block -> unit) -> int = "caml_iter_blocks_exn"

let iter_blocks f = iter_blocks_c f

let iter_blocks_exn f =
  match iter_blocks_exn_c f with
  | 0 -> Ok ()
  | n -> Error (Obj.magic n : exn)   (* re‑raise the exception value *)
```

```ocaml
(* Example client code ---------------------------------------------------- *)
open Blocksci

let () =
  iter_blocks (fun blk ->
      Printf.printf "height=%d txs=%d\n%!"
        (block_height blk)
        (block_tx_count blk))
```

The loop runs entirely in C++, the only OCaml work per block is the
execution of the user‑supplied function (which sees a cheap, reusable
`block` value).  This pattern gives you the same “vectorized‑row‑wise”
experience that pandas/Polars provide, while keeping the hot path in
native code.
